  function drawFreehand(ctx,pts,isDraft,color){const arr=(pts||[]).map(xy).filter(Boolean);if(!arr.length)return;ctx.save();ctx.strokeStyle=color||DEFAULT_COLOR;ctx.lineWidth=isDraft?2.2:2.4;ctx.lineCap="round";ctx.lineJoin="round";ctx.beginPath();ctx.moveTo(arr[0].x,arr[0].y);if(arr.length===1){ctx.lineTo(arr[0].x+.01,arr[0].y+.01)}else if(arr.length===2){ctx.lineTo(arr[1].x,arr[1].y)}else{for(let i=1;i<arr.length-1;i++){const midX=(arr[i].x+arr[i+1].x)/2,midY=(arr[i].y+arr[i+1].y)/2;ctx.quadraticCurveTo(arr[i].x,arr[i].y,midX,midY)}const prev=arr[arr.length-2],last=arr[arr.length-1];ctx.quadraticCurveTo(prev.x,prev.y,last.x,last.y)}ctx.stroke();ctx.restore()}
